compliant:
public static class MyClass
{
    public static void Print(int number)
    {
        Print(number, "\n"); // Delegate to the more specific overload
    }

    public static void Print(int number, string delimiter)
    {
        Console.Write(number);
        Console.Write(delimiter);
    }
}

